import React, { useState } from 'react';
import { navigate } from 'gatsby';
import './sign-up.css';
import { FiArrowRight } from 'react-icons/fi';
import { FaCheck } from 'react-icons/fa';
import { handleSignup } from '../../database/functions';

const i18n = {
  EN: {
    brandTitle: 'TINH HOA VIỆT',
    tagline: "Where Vietnamese Excellence Meets Global Recognition",
    features: ['Premium Vietnamese Heritage', 'Global Excellence Standards', 'Elite Community Access'],
    begin: 'Create Your Account',
    sub: 'Join the platform that recognizes Vietnamese excellence',
    fullName: 'Full Name',
    email: 'Email Address',
    password: 'Password',
    confirmPassword: 'Confirm Password',
    passwordHint: 'At least 8 characters with numbers and symbols',
    terms1: 'I agree to the ',
    tos: 'Terms of Service',
    and: ' and ',
    privacy: 'Privacy Policy',
    submit: 'Create Account',
    have: 'Already part of our community? ',
    login: 'Sign In to Your Account',
    langEN: 'EN',
    langVN: 'VN',
  },
  VN: {
    brandTitle: 'TINH HOA VIỆT',
    tagline: 'Nơi tôn vinh tinh hoa Việt Nam vươn tầm quốc tế',
    features: ['Di sản Việt Nam đẳng cấp', 'Chuẩn mực xuất sắc toàn cầu', 'Cộng đồng tinh hoa'],
    begin: 'Tạo Tài Khoản',
    sub: 'Tham gia nền tảng tôn vinh tinh hoa Việt',
    fullName: 'Họ và Tên',
    email: 'Địa chỉ Email',
    password: 'Mật khẩu',
    confirmPassword: 'Xác nhận mật khẩu',
    passwordHint: 'Tối thiểu 8 ký tự, có số và ký hiệu',
    terms1: 'Tôi đồng ý với ',
    tos: 'Điều khoản Dịch vụ',
    and: ' và ',
    privacy: 'Chính sách Bảo mật',
    submit: 'Tạo Tài Khoản Tinh Hoa',
    have: 'Đã có tài khoản? ',
    login: 'Đăng nhập tài khoản',
    langEN: 'EN',
    langVN: 'VN',
  }
};

const SignUpV2: React.FC = () => {
  const [formData, setFormData] = useState({
    fullName: '',
    email: '',
    password: '',
    confirmPassword: '',
    agree: false
  });
  const [language, setLanguage] = useState<'EN' | 'VN'>('EN');
  const [message, setMessage] = useState('');
  const t = i18n[language];

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value, type, checked } = e.target;
    setFormData(prev => ({ ...prev, [name]: type === 'checkbox' ? checked : value }));
  };

  const onSuccess = () => {
    setMessage('✅ Check your email for a verification link!');
    setTimeout(() => navigate('/sign-up'), 2000);
  };

  const onFail = (err?: string) => {
    setMessage('❌ ' + (err || 'Signup failed. Please try again.'));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    if (!formData.agree) {
      setMessage(language === 'EN'
        ? '❌ You must agree to the Terms of Service'
        : '❌ Bạn phải đồng ý với Điều khoản Dịch vụ');
      return;
    }

    if (formData.password !== formData.confirmPassword) {
      setMessage(language === 'EN' ? '❌ Passwords do not match' : '❌ Mật khẩu không khớp');
      return;
    }

    if (formData.password.length < 8) {
      setMessage(language === 'EN'
        ? '❌ Password must be at least 8 characters'
        : '❌ Mật khẩu phải có ít nhất 8 ký tự');
      return;
    }

    handleSignup({
        email: formData.email,
        password: formData.password,
        fullName: formData.fullName,
        onSuccess,
        onFail,
    })
  };

  return (
    <div className="auth-shell">
      {/* Left brand side */}
      <aside className="brand-side" aria-hidden>
        <div className="brand-sheen" />
        <div className="brand-pattern" />
        <div className="brand-wrap">
          <h1 className="brand-name">{t.brandTitle}</h1>
          <p className="brand-tag">{t.tagline}</p>
          <ul className="brand-features">
            {t.features.map((f, i) => (
              <li className="feature" key={i}>
                  <span className="tick">✓</span><span>{f}</span>
              </li>
            ))}
          </ul>
      
        </div>
      </aside>

      {/* Right form side */}
      <main className="form-side" role="main">
        <header className="form-top">
          <div className="lang-switch" role="tablist" aria-label="Language switcher">
            <button
              role="tab"
              aria-selected={language === 'EN'}
              className={`lang ${language === 'EN' ? 'active' : ''}`}
              onClick={() => setLanguage('EN')}
            >{t.langEN}</button>
            <span className="mid">|</span>
            <button
              role="tab"
              aria-selected={language === 'VN'}
              className={`lang ${language === 'VN' ? 'active' : ''}`}
              onClick={() => setLanguage('VN')}
            >{t.langVN}</button>
          </div>
        </header>

        <section className="form-wrap">
          <div className="intro">
            <h2 className="title">{t.begin}</h2>
            <p className="subtitle">{t.sub}</p>
          </div>

          <form onSubmit={handleSubmit} className="auth-form" noValidate>
            <div className="field">
              <label htmlFor="fullName">{t.fullName} <span className="req">*</span></label>
              <input
                type="text"
                id="fullName"
                name="fullName"
                value={formData.fullName}
                onChange={handleChange}
                placeholder={language === 'EN' ? 'Enter your full name' : 'Nhập họ và tên'}
                required
              />
            </div>

            <div className="field">
              <label htmlFor="email">{t.email} <span className="req">*</span></label>
              <input
                type="email"
                id="email"
                name="email"
                value={formData.email}
                onChange={handleChange}
                placeholder={language === 'EN' ? 'your.email@example.com' : 'email@vi-du.com'}
                required
              />
            </div>

            <div className="form-row">
              <div className="field">
                <label htmlFor="password">{t.password} <span className="req">*</span></label>
                <input
                  type="password"
                  id="password"
                  name="password"
                  value={formData.password}
                  onChange={handleChange}
                  placeholder={language === 'EN' ? 'Create a strong password' : 'Tạo mật khẩu mạnh'}
                  required
                  minLength={8}
                />
                <small className="hint">{t.passwordHint}</small>
              </div>

              <div className="field">
                <label htmlFor="confirmPassword">{t.confirmPassword} <span className="req">*</span></label>
                <input
                  type="password"
                  id="confirmPassword"
                  name="confirmPassword"
                  value={formData.confirmPassword}
                  onChange={handleChange}
                  placeholder={language === 'EN' ? 'Re-enter your password' : 'Nhập lại mật khẩu'}
                  required
                  minLength={8}
                />
              </div>
            </div>

            <div className="terms">
              <input
                type="checkbox"
                id="agree"
                name="agree"
                checked={formData.agree}
                onChange={handleChange}
                required
              />
              <label htmlFor="agree">
                {t.terms1}
                <a href="#terms">{t.tos}</a>
                {t.and}
                <a href="#privacy">{t.privacy}</a>
              </label>
            </div>

            <button type="submit" className="cta">
              <span>{t.submit}</span>
              <FiArrowRight className="arrow" />
            </button>

            {message && (
              <p style={{ textAlign: 'center', marginTop: 10, color: '#fff' }}>{message}</p>
            )}

            <p className="switch">
              {t.have}
              <a href="/sign-in">{t.login}</a>
            </p>
          </form>
        </section>
      </main>
    </div>
  );
};

export default SignUpV2;
